const form = $input.first().json;

const sceneTypeMap = {
  'Exterior Day':      'ext_day',
  'Exterior Night':    'ext_night',
  'Interior Day':      'int_day',
  'Interior Night':    'int_night',
  'Golden Hour':       'golden_hour',
  'Overcast':          'overcast',
  'Storm / Dramatic':  'storm'
};

const cgSubjectMap = {
  'Character / Human':          'character',
  'Vehicle':                    'vehicle',
  'Creature':                   'creature',
  'Hard Surface Object':        'hard_surface',
  'Environment / Set Extension':'environment'
};

const data = {
  shotCode:          (form['Shot Code'] || '').trim(),
  sequenceCode:      (form['Sequence Code'] || form['Shot Code']?.split('_')[0] || 'SEQ-000').trim(),
  projectId:         (form['Project ID'] || 'PROJ-001').trim(),
  plateImageUrl:     (form['Plate Image URL'] || '').trim(),
  moodDescription:   (form['Lighting Mood Description'] || '').trim(),
  sceneType:         sceneTypeMap[form['Scene Type']] || 'ext_day',
  cgSubjectType:     cgSubjectMap[form['CG Subject Type']] || 'character',
  supervisorEmail:   (form['Supervisor Email'] || '').trim(),
  requestTimestamp:  new Date().toISOString()
};

if (!data.shotCode) throw new Error('Shot Code is required');
if (!data.plateImageUrl) throw new Error('Plate Image URL is required');
if (!data.moodDescription) throw new Error('Lighting Mood Description is required');

return [{ json: data }];

const d = $input.first().json;
const mood = d.moodDescription;
const scene = d.sceneType;
const subject = d.cgSubjectType;

const variations = [
  {
    variantId:   'LLD-KEY',
    lightType:   'key_light',
    label:       'Key Light Setup',
    lightIcon:   '☀️',
    safePrompt:  JSON.stringify(`${mood}. Strong single key light source from upper left at 45 degrees, deep shadows on opposite side, rim light separating subject from background. CG ${subject} on neutral grey turntable, ${scene} lighting conditions. Photorealistic look development reference, cinema quality --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId:   'LLD-SOFT',
    lightType:   'soft_diffuse',
    label:       'Soft Diffuse Setup',
    lightIcon:   '🌥️',
    safePrompt:  JSON.stringify(`${mood}. Overcast sky dome lighting, no hard shadows, soft wrap light from all directions, subtle ambient occlusion in crevices. CG ${subject} on neutral grey turntable, ${scene} lighting conditions. Photorealistic look development reference, cinema quality --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId:   'LLD-DRAM',
    lightType:   'dramatic_contrast',
    label:       'High Contrast / Dramatic',
    lightIcon:   '🎭',
    safePrompt:  JSON.stringify(`${mood}. High contrast dramatic lighting, deep blacks, strong highlights, noir-inspired single source from side. CG ${subject} on neutral grey turntable, ${scene} lighting conditions. Photorealistic look development reference, cinema quality --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId:   'LLD-PLATE',
    lightType:   'plate_match',
    label:       'Plate Match Reference',
    lightIcon:   '🎬',
    safePrompt:  JSON.stringify(`${mood}. Lighting precisely matched to the reference plate photograph provided — same colour temperature, same shadow direction, same light intensity and falloff. CG ${subject} composited into scene, matching all plate lighting exactly. Photorealistic VFX look development reference --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId:   'LLD-COMP',
    lightType:   'comp_grade',
    label:       'Comp Grade Preview',
    lightIcon:   '🎨',
    safePrompt:  JSON.stringify(`${mood}. Final comp-graded look with colour correction, film grain, lens vignette, chromatic aberration, colour grade matching ${scene} aesthetic. CG ${subject} fully integrated into environment. Cinematic final frame look development reference --duration 5 --camerafixed true`).slice(1,-1)
  }
];

return variations.map(v => ({ json: { ...v, ...d } }));

const input = $input.first().json;

const body = {
  model: 'seedance-1-5-pro-251215',
  content: [
    { type: 'text', text: input.safePrompt },
    { type: 'image_url', image_url: { url: input.plateImageUrl } }
  ],
  generate_audio: false,
  ratio: '16:9',
  duration: 5,
  watermark: false
};

return [{
  json: {
    ...input,
    requestBody: JSON.stringify(body),
    mode: 'image_to_video'
  }
}];

const httpResult = $input.first().json;
const variantData = $('Build Lighting Request Body').first().json;
return [{ json: { ...variantData, id: httpResult.id, jobStatus: httpResult.status } }];

const input = $input.first().json;
const variantData = $('Merge Lighting Job ID + Metadata').first().json;

let videoUrl = null;
if (input.content && input.content.video_url) {
  videoUrl = input.content.video_url;
}
if (!videoUrl) {
  videoUrl = input.output_url || input.video_url || `URL not found. Job ID: ${input.id}`;
}

return [{
  json: {
    variantId:        variantData.variantId,
    lightType:        variantData.lightType,
    lightIcon:        variantData.lightIcon,
    label:            variantData.label,
    shotCode:         variantData.shotCode,
    sequenceCode:     variantData.sequenceCode,
    projectId:        variantData.projectId,
    videoUrl:         videoUrl,
    plateImageUrl:    variantData.plateImageUrl,
    moodDescription:  variantData.moodDescription,
    sceneType:        variantData.sceneType,
    cgSubjectType:    variantData.cgSubjectType,
    supervisorEmail:  variantData.supervisorEmail,
    jobId:            input.id,
    resolution:       input.resolution,
    duration:         input.duration,
    generatedAt:      new Date().toISOString(),
    tags: {
      asset_type:    'lighting_lookdev',
      light_type:    variantData.lightType,
      scene_type:    variantData.sceneType,
      cg_subject:    variantData.cgSubjectType,
      shot_code:     variantData.shotCode,
      ai_generated:  true,
      review_status: 'pending_review',
      workflow:      'lighting_lookdev_builder'
    }
  }
}];

const items = $input.all();
const metaItems = $('Build Lighting Asset Metadata').all();

// Build lookbook HTML content for Confluence
const lookbookRows = metaItems.map(item => {
  const d = item.json;
  return `<tr>
    <td><strong>${d.lightIcon} ${d.label}</strong></td>
    <td>${d.lightType}</td>
    <td><a href="${d.videoUrl}">Watch Reference</a></td>
    <td>${d.resolution || '720p'}</td>
    <td>${d.generatedAt}</td>
  </tr>`;
}).join('\n');

const lookbookHtml = `
<h1>🎬 Lighting Look Development – ${metaItems[0].json.shotCode}</h1>
<p><strong>Sequence:</strong> ${metaItems[0].json.sequenceCode} | <strong>Project:</strong> ${metaItems[0].json.projectId}</p>
<p><strong>Scene Type:</strong> ${metaItems[0].json.sceneType} | <strong>CG Subject:</strong> ${metaItems[0].json.cgSubjectType}</p>
<p><strong>Lighting Mood:</strong> ${metaItems[0].json.moodDescription}</p>
<p><strong>Reference Plate:</strong> <a href="${metaItems[0].json.plateImageUrl}">View Plate</a></p>
<h2>Generated Lighting Variations</h2>
<table>
  <thead>
    <tr><th>Variation</th><th>Light Type</th><th>Video</th><th>Resolution</th><th>Generated</th></tr>
  </thead>
  <tbody>
    ${lookbookRows}
  </tbody>
</table>
<h2>Usage Notes</h2>
<p>These AI-generated references are for look development guidance only. Use as visual targets when setting up CG lighting rigs. Match colour temperature, shadow direction, and light intensity to the selected option.</p>
<p><em>Generated by AI Lighting Look Dev Builder — ${new Date().toISOString()}</em></p>
`;

const slackLines = metaItems.map(item => {
  const d = item.json;
  return `${d.lightIcon} *${d.label}* (${d.variantId})\n> 🎬 <${d.videoUrl}|Watch Reference>\n> 💡 Type: ${d.lightType}\n> 📅 ${d.generatedAt}`;
}).join('\n\n');

const first = metaItems[0].json;

return [{
  json: {
    shotCode:        first.shotCode,
    sequenceCode:    first.sequenceCode,
    projectId:       first.projectId,
    moodDescription: first.moodDescription,
    sceneType:       first.sceneType,
    cgSubjectType:   first.cgSubjectType,
    supervisorEmail: first.supervisorEmail,
    plateImageUrl:   first.plateImageUrl,
    lookbookHtml:    lookbookHtml,
    slackLines:      slackLines,
    totalVariations: metaItems.length,
    generatedAt:     new Date().toISOString()
  }
}];

